import{_ as t,o as i,c as s,a3 as a}from"./chunks/framework.LBeL10WQ.js";const g=JSON.parse('{"title":"Jeu Concours","description":"","frontmatter":{"title":"Jeu Concours"},"headers":[],"relativePath":"advertisers/co-branded-contest/index.md","filePath":"advertisers/co-branded-contest/index.md"}'),o={name:"advertisers/co-branded-contest/index.md"};function r(n,e,l,d,u,c){return i(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="jeu-concours" tabindex="-1">Jeu Concours <a class="header-anchor" href="#jeu-concours" aria-label="Permalink to &quot;Jeu Concours&quot;">​</a></h1><p>Le dispositif qui combine <strong>notoriété</strong>, <strong>acquisition de leads qualifiés</strong> et <strong>conversion immédiate</strong> — grâce à la caution d&#39;un e-commerçant partenaire.</p><hr><h2 id="mecaniques-disponibles" tabindex="-1">Mécaniques disponibles <a class="header-anchor" href="#mecaniques-disponibles" aria-label="Permalink to &quot;Mécaniques disponibles&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>🎟️ Ticket d&#39;Or</strong><p>Un ticket gagnant est inséré directement dans les colis du distributeur. La surprise au moment de l&#39;unboxing maximise l&#39;impact émotionnel.</p></div><div class="gi-value-card"><strong>🎡 Roue de la Fortune</strong><p>Mécanique ludique activée via un QR code (<em>&quot;Flashez pour tourner la roue&quot;</em>). Fort taux de participation et viralité naturelle.</p></div><div class="gi-value-card"><strong>🧠 Quiz / Profil</strong><p>Format interactif (<em>&quot;Quel est votre profil ?&quot;</em>) qui génère un engagement exceptionnel et qualifie les leads en même temps.</p></div></div><div class="tip custom-block"><p class="custom-block-title">Exemple terrain</p><p>AJY (marque bien-être) a obtenu un <strong>taux de scan de 21,6%</strong> avec un quiz <em>&quot;Découvrez votre Dosha&quot;</em> — l&#39;un des meilleurs scores observés sur le réseau.</p></div><hr><h2 id="pourquoi-lancer-un-jeu-concours" tabindex="-1">Pourquoi lancer un jeu concours ? <a class="header-anchor" href="#pourquoi-lancer-un-jeu-concours" aria-label="Permalink to &quot;Pourquoi lancer un jeu concours ?&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>📊 Acquisition de Leads (Opt-in)</strong><p>En échange de leur participation, les joueurs acceptent de recevoir vos offres. Vous enrichissez votre CRM avec des contacts <strong>consentants et qualifiés</strong> par le comportement d&#39;achat du distributeur.</p></div><div class="gi-value-card"><strong>💰 Conversion : aucun perdant</strong><p>Chaque participant reçoit un <strong>code promo de consolation</strong> (ex: MERCI15). Cela transforme une mécanique gratuite en ventes immédiates — même pour ceux qui ne gagnent pas le gros lot.</p></div><div class="gi-value-card"><strong>❤️ Engagement Fort</strong><p>La gamification crée un lien émotionnel positif entre votre marque et l&#39;audience du distributeur. Vous bénéficiez de sa crédibilité auprès de sa communauté.</p></div></div><hr><h2 id="votre-investissement" tabindex="-1">Votre investissement <a class="header-anchor" href="#votre-investissement" aria-label="Permalink to &quot;Votre investissement&quot;">​</a></h2><p>En dehors du budget média, vous fournissez deux éléments :</p><div class="gi-value-grid"><div class="gi-value-card"><strong>🏆 La Dotation (Gros lots)</strong><p>Le produit d&#39;appel qui attire les joueurs. Exemple : <em>&quot;Gagnez un an de produits&quot;</em> ou <em>&quot;3 × 100€ de bons d&#39;achat&quot;</em>. Vous gérez l&#39;envoi aux gagnants après le tirage au sort.</p></div><div class="gi-value-card"><strong>🎟️ La Récompense de consolation</strong><p>Un code promo générique (ex: <code>MERCI15</code>) offert à <em>tous</em> les participants. Simple à préparer, fort impact sur la conversion.</p></div></div><hr><h2 id="workflow-en-5-etapes" tabindex="-1">Workflow en 5 étapes <a class="header-anchor" href="#workflow-en-5-etapes" aria-label="Permalink to &quot;Workflow en 5 étapes&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Brief &amp; Définition de l&#39;offre</h3><p>Via la plateforme, fournissez les lots (dotation + code promo de consolation), les visuels (packshots, logo HD) et choisissez le distributeur partenaire.</p></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Mise en place (Distributeur)</h3><p>Le distributeur crée une landing page co-brandée sur son site et active ses canaux de trafic (newsletter, bannières, push web) pour diriger sa communauté vers le jeu.</p></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Collecte de l&#39;Opt-in (RGPD)</h3><p>À l&#39;inscription, le participant coche une case explicite :</p><blockquote><em>☑ J&#39;accepte de recevoir les offres commerciales du partenaire [Nom de votre Marque].</em></blockquote><p>Seuls les participants ayant coché cette case vous sont transmis et facturés.</p></div></div><div class="gi-step"><div class="gi-step-num">4</div><div class="gi-step-body"><h3>Transfert de Data &amp; Activation</h3><p>À la fin de la campagne, le distributeur vous transmet le fichier CSV sécurisé des leads opt-in via getinside. Intégrez-les dans votre CRM (Mailchimp, Klaviyo…) et envoyez <strong>immédiatement</strong> l&#39;email de bienvenue avec le code promo promis — le timing est clé pour maximiser la conversion.</p></div></div><div class="gi-step"><div class="gi-step-num done">5</div><div class="gi-step-body"><h3>Tirage au sort</h3><p>Vous effectuez le tirage au sort des gagnants des gros lots et gérez l&#39;expédition des récompenses directement auprès d&#39;eux.</p></div></div><div class="warning custom-block"><p class="custom-block-title">RGPD — règles impératives</p><ul><li>La case opt-in ne doit <strong>jamais</strong> être pré-cochée.</li><li>Seuls les participants l&#39;ayant cochée volontairement vous sont transmis.</li><li>getinside fournit les modèles de mentions légales validés par des juristes.</li></ul></div><hr><h2 id="tarification" tabindex="-1">Tarification <a class="header-anchor" href="#tarification" aria-label="Permalink to &quot;Tarification&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Poste</th><th style="text-align:left;">Coût</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Frais de plateforme</strong></td><td style="text-align:left;">12% du budget média investi</td></tr><tr><td style="text-align:left;"><strong>Studio Créatif</strong> (optionnel)</td><td style="text-align:left;">Forfait 550€ HT par campagne</td></tr><tr><td style="text-align:left;"><strong>Dotation</strong></td><td style="text-align:left;">À votre charge (lots + expédition aux gagnants)</td></tr></tbody></table><hr><h2 id="pourquoi-passer-par-getinside" tabindex="-1">Pourquoi passer par getinside ? <a class="header-anchor" href="#pourquoi-passer-par-getinside" aria-label="Permalink to &quot;Pourquoi passer par getinside ?&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>⚡ Clé en Main</strong><p>getinside coordonne la mise en place technique avec le distributeur (landing page, flux de données). Vous fournissez les lots et les visuels — c&#39;est tout.</p></div><div class="gi-value-card"><strong>⚖️ Conformité RGPD</strong><p>La collecte de données partagées est un enjeu juridique majeur. Nos modèles d&#39;opt-in validés par des juristes vous protègent et garantissent l&#39;exploitabilité de la base collectée.</p></div></div>',27)])])}const v=t(o,[["render",r]]);export{g as __pageData,v as default};
